const questionRaw = $input.first().json.body.question || "";
const question = questionRaw.toLowerCase().trim();

// ======= ⚙️ Hàm bỏ dấu tiếng Việt =======
function removeDiacritics(str) {
  return str
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/Đ/g, "D");
}

// Bỏ dấu cho input để check so khớp
const questionNormalized = removeDiacritics(question);

// ======= 🧠 Danh sách từ khóa liên quan Tarot =======
const keywords = [
  "tinh cam","moi quan he","hop nhau","loi khuyen","nen lam gi","nghi gi ve",
  "tim hieu","de y den","an tuong","xuat hien","quay lai","nguoi thu ba",
  "qua khu","tuong lai","sap toi","ngoai tinh","gia dinh","lua doi","mqh",
  "suc khoe","cong viec","du hoc","vuot qua","nguoi yeu cu","crush","yeu minh",
  "thich minh","co ai khac","dinh menh","duyen phan","co hoi","thanh cong",
  "doi viec","thi cu","dinh huong","muc tieu","so phan","vu tru","stress",
  "chua lanh","thang tien","tai chinh","phong van","kinh doanh","may man",
  "vo","chong"
];

// ======= 🚫 Từ nhạy cảm / bị chặn =======
const banned = [
  "chet","tu tu","giet","ma","bua","yem","ngai","phap su","hai nguoi","danh de","trung so"
];

// ======= 🧩 Kiểm tra nhanh =======
const tooShort = questionNormalized.length < 15;
const hasBanned = banned.some(b => questionNormalized.includes(b));
const hasKeyword = keywords.some(k => questionNormalized.includes(k));

// ======= 🧠 Logic quyết định =======
let isTarot = false;

if (!tooShort && !hasBanned && hasKeyword) {
  isTarot = true;
}

// ======= 🔚 Output cực gọn =======
return [{ isTarot }];

for (const item of $input.all()) {

  const userProfile = $('Webhook').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn', user_persona: '' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const recentEvents = userProfile.user_persona;

  let personaSection = '';
  if (recentEvents && recentEvents.trim() !== '') {
    personaSection = `\n\n### [HỒ SƠ VÀ BỐI CẢNH KHÁCH HÀNG]\n${recentEvents}`;
  }

  const mySystemPrompt = `## ROLE: Tarot Question Linter & Moderator
## USER INFO: Tên: ${userName}, Giới tính: ${userGender}. Quy tắc xưng hô: BẠN BẮT BUỘC PHẢI tự xưng là "mình" và gọi khách hàng là "bạn" (có thể kết hợp gọi tên ${userName}) một cách tự nhiên.\n\n${personaSection}\n\n## TASK: Đánh giá [CÂU HỎI] của người dùng có phù hợp để trải bài Tarot CÓ/KHÔNG (Yes/No Question) hay không.

## QUY TẮC ĐÁNH GIÁ:
1. isValid = true:
- Câu hỏi CÓ DẠNG YES/NO (Có/Không) hoặc mang tính lựa chọn, quyết định.
- Chủ đề rõ ràng liên quan đến đời sống, công việc, tình cảm, định hướng cá nhân.
- Khi isValid = true, trường reason BẮT BUỘC phải là "ok".

2. isValid = false:
- Câu hỏi KHÔNG PHẢI dạng Yes/No (ví dụ: câu hỏi mở như "Tôi phải làm gì", "Tương lai của tôi thế nào").
- Câu hỏi quá ngắn, trống rỗng, vô nghĩa, spam (ví dụ: "hi", "asdasd").
- Chủ đề không phù hợp (hỏi bài tập, nấu ăn, code, chính trị, thô tục).
- Khi isValid = false, reason phải là một câu giải thích lịch sự, ngắn gọn bằng tiếng Việt lý do không phù hợp.

## OUTPUT FORMAT (JSON ONLY - KHÔNG bọc block code):
{"isValid": true, "reason": "ok"}`;

  const question = $('Check câu hỏi').first().json.body.question || "";

  const myUserPrompt = `### [CÂU HỎI ĐẦU VÀO CỦA KHÁCH HÀNG]
"${question}"

Hãy phân tích và trả về đối tượng JSON đúng định dạng.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      {
        role: "system",
        content: mySystemPrompt
      },
      {
        role: "user",
        content: myUserPrompt
      }
    ],
    temperature: 0
  };
}

return $input.all();

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = false;
  let reason = "Câu hỏi chưa rõ ràng hoặc không liên quan đến Tarot.";

  // 1. Trích xuất kết quả từ API
  let rawText = "";
  if (data.choices && data.choices[0] && data.choices[0].message) {
    rawText = data.choices[0].message.content || "";
  } else {
    rawText = data.output || data.text || "";
  }

  if (typeof rawText === 'object') {
    rawText = JSON.stringify(rawText);
  }
  rawText = rawText.trim();

  // Loại bỏ markdown code block nếu có
  if (rawText.includes('```')) {
    rawText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  }

  try {
    const parsed = JSON.parse(rawText);
    isValid = parsed.isValid;
    reason = parsed.reason || "ok";
  } catch (e) {
    // Fallback bằng Regex nếu không parse được JSON
    const lowerText = rawText.toLowerCase();
    if (lowerText.includes('"isvalid": true') || lowerText.includes('isvalid: true') || lowerText.includes('true')) {
      isValid = true;
      reason = "ok";
    } else {
      isValid = false;
      const match = rawText.match(/"reason"\s*:\s*"([^"]+)"/i);
      if (match && match[1]) {
        reason = match[1];
      }
    }
  }

  // 2. Ép kiểu chuẩn
  if (typeof isValid === 'string') {
    isValid = (isValid.toLowerCase() === 'true');
  } else {
    isValid = Boolean(isValid);
  }

  // 3. Chuẩn hóa giá trị
  if (isValid) {
    reason = "ok";
  } else if (!reason || reason === "ok" || reason === "undefined") {
    reason = "Câu hỏi không phù hợp. Vui lòng đặt câu hỏi liên quan đến chủ đề Tarot.";
  }

  results.push({
    json: {
      output: {
        isValid: isValid,
        reason: reason
      }
    }
  });
}

return results;

for (const item of $input.all()) {
  const question = $('Luận giải tarot').first().json.body.question || "";
  const cards = item.json.cards || [];

  // Kiểm tra và lấy Lịch sử trải bài từ node Lấy Lịch Sử D1
  let isFollowUp = false;
  let previousQuestions = [];
  let historyText = "Chưa có cuộc trò chuyện nào trước đó.";
  let cardsListText = "";

  try {
    const historyNode = $('Lấy Lịch Sử D1').first().json;
    if (historyNode && historyNode.exists) {
      isFollowUp = true;

      const cardsList = (historyNode.cards_payload || []).map(c => `${c.name || c.card_name} (${c.orientation || 'Xuôi'})`).join(', ');
      cardsListText = `Lá bài đã bốc: ${cardsList}`;

      previousQuestions.push(historyNode.question);

      if (historyNode.interpretation) {
        const regex = /Lữ khách hỏi tiếp: "(.*?)"/g;
        let match;
        while ((match = regex.exec(historyNode.interpretation)) !== null) {
          previousQuestions.push(match[1]);
        }
      }

      const questionsStr = previousQuestions.map((q, i) => `Lần ${i+1}: "${q}"`).join('\n');
      historyText = `Các câu hỏi lữ khách đã hỏi trước đó:\n${questionsStr}`;
    }
  } catch (e) {}


  // Lấy thông tin userProfile
  const userProfile = $('Luận giải tarot').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn', user_persona: '' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const recentEvents = userProfile.user_persona;

  let personaSection = '';
  if (recentEvents && recentEvents.trim() !== '') {
    personaSection = '\n\n### [HỒ SƠ VÀ BỐI CẢNH KHÁCH HÀNG]\n' + recentEvents;
  }

  const userInfoPrompt = '\n\n## USER INFO: Tên: ' + userName + ', Giới tính: ' + userGender + '. Quy tắc xưng hô: BẠN BẮT BUỘC PHẢI tự xưng là \"mình\" và gọi khách hàng là \"bạn\" (có thể kết hợp gọi tên ' + userName + ') một cách tự nhiên.' + personaSection;

  let mySystemPrompt = "";
  if (!isFollowUp) {
    mySystemPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm và chuyên nghiệp sử dụng bộ bài Rider–Waite. Hãy giải đáp câu hỏi dạng CÓ/KHÔNG (Yes/No Question) của lữ khách dựa trên các lá bài đã bốc và ý nghĩa tương ứng được cung cấp.

## HƯỚNG DẪN LUẬN GIẢI:
1. Xác định năng lượng tổng quan thiên về "Có" (Yes), "Không" (No), hoặc "Có thể" (Maybe) dựa vào ý nghĩa của các lá bài.
2. Với mỗi lá bài, hãy lồng ghép cả "mặt sáng" và "bài học cần học" để mang lại góc nhìn đa chiều, tuyệt đối không mang xu hướng mê tín dị đoan.
3. Giọng văn con người trầm ổn, đồng cảm, chân thành, tựa như một người bạn tâm giao đang trò chuyện thật sự.
4. TUYỆT ĐỐI KHÔNG nhắc đến các từ liên quan đến AI, hệ thống, thuật toán, máy tính, hoặc "Xuôi". (Luôn dùng các cách gọi khác như: Hướng thuận, mặt thuận lợi, v.v.).
5. Trình bày đẹp mắt bằng Markdown. Giới hạn độ dài trong khoảng 800 tokens.

## CẤU TRÚC BẮT BUỘC (GIỮ NGUYÊN FORMAT MARKDOWN):
---
Lời chào mở đầu (1–2 câu)
### 1. Tổng quan năng lượng của câu hỏi (Kết luận Yes/No/Maybe và lý do) (3-4 câu)
### 2. Phân tích các lá bài đã bốc (3-4 câu cho mỗi lá)
### 3. Lời khuyên từ trái tim (2-3 câu)
→ Kết thúc bằng 1–2 câu hỏi tự vấn` + userInfoPrompt;
  } else {
    mySystemPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm. Lữ khách đang có thắc mắc tiếp nối về trải bài Tarot Yes/No trước đó. Hãy trực tiếp giải đáp thắc mắc mới này.

## HƯỚNG DẪN LUẬN GIẢI:
1. TRỰC TIẾP đi vào vấn đề giải đáp câu hỏi mới, KHÔNG CẦN lặp lại lời chào mở đầu sến súa.
2. Trình bày nội dung một cách tự nhiên, linh hoạt, giống như một cuộc trò chuyện sâu sắc. KHÔNG tuân theo outline rập khuôn như lần đầu.
3. Hãy ngắt đoạn linh hoạt cho đỡ nhàm chán, có thể dùng bullet points tự do nếu phù hợp.
4. Liên kết câu trả lời với ý nghĩa các lá bài đã bốc ban đầu và các vấn đề lữ khách đã hỏi trước đó để tạo sự liền mạch. Tuân thủ tuyệt đối ý nghĩa gốc của các lá bài.
5. Giọng văn trầm ổn, đồng cảm, chân thành và mang tính chữa lành. TUYỆT ĐỐI KHÔNG nhắc đến các từ liên quan đến AI, thuật toán.` + userInfoPrompt;
  }

  let cardsSection = "";
  if (cards.length > 0) {
    cardsSection = `### [CHI TIẾT TRẢI BÀI & Ý NGHĨA GỐC TỪ D1]\n`;
    cards.forEach((c, index) => {
      cardsSection += `- **Lá bài ${index + 1}**: ${c.name || c.card_name || "—"} (${c.orientation || "Xuôi"})\n  * Ý nghĩa cốt lõi: ${c.meaning || "—"}\n  * Dấu hiệu Yes/No: ${c.yes_no_meaning || "Không xác định"}\n\n`;
    });
  }

  const myUserPrompt = `### [CÂU HỎI MỚI CỦA LỮ KHÁCH]
"${question}"

${cardsSection}

### [BỐI CẢNH LỊCH SỬ CÂU HỎI TRƯỚC ĐÓ]
${historyText}

Hãy thấu cảm và giải đáp câu hỏi mới của lữ khách.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      {
        role: "system",
        content: mySystemPrompt
      },
      {
        role: "user",
        content: myUserPrompt
      }
    ],
    temperature: 0.7
  };
}

return $input.all();

